        .from(dashboards)
        .where(and(
          eq(dashboards.customerId, customerId),
          eq(dashboards.userId, userId)
        ))
        .orderBy(desc(dashboards.updatedAt));
    }
    return await db
      .select()
      .from(dashboards)
      .where(eq(dashboards.customerId, customerId))
      .orderBy(desc(dashboards.updatedAt));
