import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { TrendingUp, AlertTriangle, Sparkles, FileText } from "lucide-react";
import { formatDistanceToNow } from "date-fns";

interface InsightCardProps {
  insight: {
    id: string;
    type: "trend" | "anomaly" | "forecast" | "summary";
    title: string;
    content: string;
    severity: "positive" | "negative" | "neutral";
    confidence: number;
    generatedAt: Date;
  };
}

export function InsightCard({ insight }: InsightCardProps) {
  const typeConfig = {
    trend: {
      icon: TrendingUp,
      color: "border-chart-1",
      bgColor: "bg-chart-1/5",
      label: "Trend Analysis",
    },
    anomaly: {
      icon: AlertTriangle,
      color: "border-chart-4",
      bgColor: "bg-chart-4/5",
      label: "Anomaly Detected",
    },
    forecast: {
      icon: Sparkles,
      color: "border-chart-3",
      bgColor: "bg-chart-3/5",
      label: "Forecast",
    },
    summary: {
      icon: FileText,
      color: "border-chart-2",
      bgColor: "bg-chart-2/5",
      label: "Summary",
    },
  };

  const severityColors = {
    positive: "bg-green-500/10 text-green-700 dark:text-green-400 border-green-500/20",
    negative: "bg-red-500/10 text-red-700 dark:text-red-400 border-red-500/20",
    neutral: "bg-blue-500/10 text-blue-700 dark:text-blue-400 border-blue-500/20",
  };

  const config = typeConfig[insight.type];
  const Icon = config.icon;

  return (
    <Card
      className={`border-l-4 ${config.color} ${config.bgColor}`}
      data-testid={`insight-card-${insight.id}`}
    >
      <CardHeader className="pb-3">
        <div className="flex items-start justify-between gap-3">
          <div className="flex items-start gap-3 flex-1">
            <div className={`flex h-10 w-10 items-center justify-center rounded-full ${config.bgColor} shrink-0`}>
              <Icon className="h-5 w-5" />
            </div>
            <div className="flex-1 space-y-1">
              <div className="flex items-center gap-2 flex-wrap">
                <h3 className="font-semibold text-lg">{insight.title}</h3>
                <Badge variant="outline" className="text-xs">
                  {config.label}
                </Badge>
              </div>
              <div className="flex items-center gap-2 text-xs text-muted-foreground">
                <span>{formatDistanceToNow(insight.generatedAt, { addSuffix: true })}</span>
                <span>•</span>
                <span className="font-mono">{(insight.confidence * 100).toFixed(0)}% confidence</span>
              </div>
            </div>
          </div>
          <Badge
            variant="outline"
            className={severityColors[insight.severity]}
            data-testid={`badge-severity-${insight.severity}`}
          >
            {insight.severity}
          </Badge>
        </div>
      </CardHeader>
      <CardContent>
        <p className="text-base leading-relaxed">{insight.content}</p>
      </CardContent>
    </Card>
  );
}

client/src/components/dashboard/chart-ca.content:
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { MoreVertical, Maximize2, Download, Settings } from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  LineChart,
  Line,
  BarChart,
  Bar,
  PieChart,
  Pie,
  Cell,
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";
import { useRef } from "react";
import { exportToPNG, exportChartData } from "@/lib/export-utils";
import { useToast } from "@/hooks/use-toast";

interface ChartCardProps {
  title: string;
  type: "line" | "bar" | "pie" | "area";
  description?: string;
}

export function ChartCard({ title, type, description }: ChartCardProps) {
  const chartRef = useRef<HTMLDivElement>(null);
  const { toast } = useToast();
  // Mock data - will be replaced with real data
  const lineData = [
    { month: "Jan", value: 4500 },
    { month: "Feb", value: 5200 },
    { month: "Mar", value: 4800 },
    { month: "Apr", value: 5800 },
    { month: "May", value: 5300 },
    { month: "Jun", value: 6100 },
  ];

  const barData = [
    { region: "North", sales: 4200 },
    { region: "South", sales: 3800 },
    { region: "East", sales: 5100 },
    { region: "West", sales: 4600 },
  ];

  const pieData = [
    { name: "Electronics", value: 42 },
    { name: "Clothing", value: 28 },
    { name: "Food", value: 18 },
    { name: "Other", value: 12 },
  ];

  const areaData = [
    { month: "Jan", customers: 120 },
    { month: "Feb", customers: 135 },
    { month: "Mar", customers: 128 },
    { month: "Apr", customers: 145 },
    { month: "May", customers: 152 },
    { month: "Jun", customers: 165 },
  ];

  const COLORS = ["hsl(var(--chart-1))", "hsl(var(--chart-2))", "hsl(var(--chart-3))", "hsl(var(--chart-4))"];

  const getChartData = () => {
    switch (type) {
      case "line":
        return lineData;
      case "bar":
        return barData;
      case "pie":
        return pieData;
      case "area":
        return areaData;
      default:
        return [];
    }
  };

  const handleExportImage = async () => {
    if (!chartRef.current) return;

    try {
      await exportToPNG(chartRef.current, `${title}-chart`);
      toast({
        title: "Export successful",
        description: `${title} exported as PNG image.`,
      });
    } catch (error) {
      toast({
        title: "Export failed",
        description: "Failed to export chart. Please try again.",
        variant: "destructive",
      });
    }
  };

  const handleExportData = async () => {
    try {
      const data = getChartData();
      await exportChartData(data, title);
      toast({
        title: "Export successful",
        description: `${title} data exported to Excel.`,
      });
    } catch (error) {
      console.error('Export error:', error);
      toast({
        title: "Export failed",
        description: "Failed to export data. Please try again.",
        variant: "destructive",
      });
    }
  };

  const renderChart = () => {
    switch (type) {
      case "line":
        return (
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={lineData}>
              <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" opacity={0.3} />
              <XAxis dataKey="month" stroke="hsl(var(--muted-foreground))" fontSize={12} />
              <YAxis stroke="hsl(var(--muted-foreground))" fontSize={12} />
              <Tooltip
                contentStyle={{
                  backgroundColor: "hsl(var(--popover))",
                  border: "1px solid hsl(var(--border))",
                  borderRadius: "var(--radius)",
                }}
              />
              <Line
                type="monotone"
                dataKey="value"
                stroke="hsl(var(--chart-1))"
                strokeWidth={2}
                dot={{ fill: "hsl(var(--chart-1))" }}
              />
            </LineChart>
          </ResponsiveContainer>
        );

      case "bar":
        return (
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={barData}>
              <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" opacity={0.3} />
              <XAxis dataKey="region" stroke="hsl(var(--muted-foreground))" fontSize={12} />
              <YAxis stroke="hsl(var(--muted-foreground))" fontSize={12} />
              <Tooltip
                contentStyle={{
                  backgroundColor: "hsl(var(--popover))",
                  border: "1px solid hsl(var(--border))",
                  borderRadius: "var(--radius)",
                }}
              />
              <Bar dataKey="sales" fill="hsl(var(--chart-2))" radius={[8, 8, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        );

      case "pie":
        return (
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={pieData}
                cx="50%"
                cy="50%"
                labelLine={false}
                label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                outerRadius={100}
                fill="#8884d8"
                dataKey="value"
              >
                {pieData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip
                contentStyle={{
                  backgroundColor: "hsl(var(--popover))",
                  border: "1px solid hsl(var(--border))",
                  borderRadius: "var(--radius)",
                }}
              />
            </PieChart>
          </ResponsiveContainer>
        );

      case "area":
        return (
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={areaData}>
              <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" opacity={0.3} />
              <XAxis dataKey="month" stroke="hsl(var(--muted-foreground))" fontSize={12} />
              <YAxis stroke="hsl(var(--muted-foreground))" fontSize={12} />
              <Tooltip
                contentStyle={{
                  backgroundColor: "hsl(var(--popover))",
                  border: "1px solid hsl(var(--border))",
                  borderRadius: "var(--radius)",
                }}
              />
              <Area
                type="monotone"
                dataKey="customers"
                stroke="hsl(var(--chart-3))"
                fill="hsl(var(--chart-3))"
                fillOpacity={0.3}
              />
            </AreaChart>
          </ResponsiveContainer>
        );
    }
  };

  return (
    <Card className="flex flex-col hover-elevate" data-testid={`chart-card-${title.toLowerCase().replace(/\s+/g, "-")}`}>
      <CardHeader className="flex flex-row items-start justify-between space-y-0 pb-4">
        <div className="space-y-1">
          <CardTitle className="text-xl">{title}</CardTitle>
          {description && <CardDescription>{description}</CardDescription>}
        </div>
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="icon" data-testid="button-chart-menu">
              <MoreVertical className="h-4 w-4" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuItem data-testid="menu-item-expand">
              <Maximize2 className="h-4 w-4 mr-2" />
              Expand
            </DropdownMenuItem>
            <DropdownMenuItem data-testid="menu-item-configure">
              <Settings className="h-4 w-4 mr-2" />
              Configure
            </DropdownMenuItem>
            <DropdownMenuItem onClick={handleExportImage} data-testid="menu-item-export-image">
