server/lib/analytics/trend-analysis.ts.content:
export interface TrendAnalysisResult {
  trend: 'increasing' | 'decreasing' | 'stable';
  slope: number;
  confidence: number;
  predictions: Array<{ x: any; y: number }>;
  changeRate: number;
}

export class TrendAnalyzer {
  static analyzeTrend(data: any[], xField: string, yField: string): TrendAnalysisResult {
    const points = data.map((row, idx) => ({
      x: idx,
      y: Number(row[yField]) || 0
    }));

    const { slope, intercept } = this.linearRegression(points);
    const predictions = this.generatePredictions(points, slope, intercept, 5);

    return {
      trend: slope > 0.1 ? 'increasing' : slope < -0.1 ? 'decreasing' : 'stable',
      slope,
      confidence: this.calculateRSquared(points, slope, intercept),
      predictions,
      changeRate: this.calculateChangeRate(points)
    };
  }

  private static linearRegression(points: Array<{ x: number; y: number }>) {
    const n = points.length;
    const sumX = points.reduce((sum, p) => sum + p.x, 0);
    const sumY = points.reduce((sum, p) => sum + p.y, 0);
    const sumXY = points.reduce((sum, p) => sum + (p.x * p.y), 0);
    const sumX2 = points.reduce((sum, p) => sum + (p.x * p.x), 0);

    const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
    const intercept = (sumY - slope * sumX) / n;

    return { slope, intercept };
  }

  private static calculateRSquared(
    points: Array<{ x: number; y: number }>,
    slope: number,
    intercept: number
  ): number {
    const meanY = points.reduce((sum, p) => sum + p.y, 0) / points.length;

    const totalSS = points.reduce((sum, p) => sum + Math.pow(p.y - meanY, 2), 0);
    const residualSS = points.reduce((sum, p) => {
      const predicted = slope * p.x + intercept;
      return sum + Math.pow(p.y - predicted, 2);
    }, 0);

    return 1 - (residualSS / totalSS);
  }

  private static generatePredictions(
    points: Array<{ x: number; y: number }>,
    slope: number,
    intercept: number,
    count: number
  ) {
    const lastX = points[points.length - 1].x;
    const predictions = [];

    for (let i = 1; i <= count; i++) {
      const x = lastX + i;
      const y = slope * x + intercept;
      predictions.push({ x, y: Math.max(0, y) });
    }

    return predictions;
  }

  private static calculateChangeRate(points: Array<{ x: number; y: number }>): number {
    if (points.length < 2) return 0;

    const first = points[0].y;
    const last = points[points.length - 1].y;

    return first !== 0 ? ((last - first) / first) * 100 : 0;
  }
}

server/dashboard-sharing-routes.ts.content:
import { Router } from 'express';
import { authenticateUser } from './middleware/auth';
import { storage } from './storage';
import crypto from 'crypto';
import bcrypt from 'bcryptjs';

const router = Router();

// Create share link
router.post('/api/dashboards/:id/share', authenticateUser, async (req, res) => {
  try {
    const customerId = req.user!.customerId;
    const { expiresIn, isPublic, password, allowedEmails, permissions } = req.body;

    const dashboard = await storage.getDashboard(req.params.id, customerId);
    if (!dashboard) {
      return res.status(404).json({ error: 'Dashboard not found' });
    }

    const shareToken = crypto.randomBytes(32).toString('hex');
    const expiresAt = expiresIn ? new Date(Date.now() + expiresIn * 1000) : null;
    const hashedPassword = password ? await bcrypt.hash(password, 10) : null;

    const share = await storage.createDashboardShare({
      dashboardId: req.params.id,
      shareToken,
      expiresAt,
      isPublic,
      password: hashedPassword,
      allowedEmails,
      permissions: permissions || { canEdit: false, canExport: true },
      createdBy: req.user!.id,
    });

    res.json({
      shareUrl: `${req.protocol}://${req.get('host')}/shared/${shareToken}`,
      share,
    });
  } catch (error: any) {
    res.status(400).json({ error: error.message });
  }
});

// Get dashboard by share token
router.get('/api/shared/:token', async (req, res) => {
  try {
    const share = await storage.getDashboardShareByToken(req.params.token);

    if (!share) {
      return res.status(404).json({ error: 'Share not found' });
    }

    if (share.expiresAt && new Date() > share.expiresAt) {
      return res.status(410).json({ error: 'Share link expired' });
    }

    const dashboard = await storage.getDashboardById(share.dashboardId);
    res.json({ dashboard, share, requiresPassword: !!share.password });
  } catch (error: any) {
    res.status(400).json({ error: error.message });
  }
});

// Verify password for shared dashboard
router.post('/api/shared/:token/verify', async (req, res) => {
  try {
    const { password } = req.body;
    const share = await storage.getDashboardShareByToken(req.params.token);

    if (!share || !share.password) {
      return res.status(400).json({ error: 'Invalid request' });
    }

    const isValid = await bcrypt.compare(password, share.password);
    res.json({ valid: isValid });
  } catch (error: any) {
    res.status(400).json({ error: error.message });
  }
});

// Revoke share link
router.delete('/api/dashboards/:id/share/:shareId', authenticateUser, async (req, res) => {
  try {
    await storage.deleteDashboardShare(req.params.shareId);
    res.json({ success: true });
  } catch (error: any) {
    res.status(400).json({ error: error.message });
  }
});

export default router;

