const router = Router();

// Create data source
router.post('/api/data-sources', authenticateUser, requireRole(['customer_admin', 'analyst', 'super_admin']), async (req, res) => {
  try {
    const customerId = req.user!.customerId;

    const dataSource = await storage.createDataSource({
      ...req.body,
      customerId,
    });

