import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Label } from '@/components/ui/label';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { useDatasets } from '@/lib/api-hooks';
import { 
  LineChart, Line, BarChart, Bar, PieChart, Pie, AreaChart, Area,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Cell 
} from 'recharts';

interface ChartBuilderProps {
  onSave: (config: any) => void;
}

export function AdvancedChartBuilder({ onSave }: ChartBuilderProps) {
  const { data: datasets } = useDatasets();

  const [selectedDataset, setSelectedDataset] = useState<string>('');
  const [chartType, setChartType] = useState<'line' | 'bar' | 'pie' | 'area'>('bar');
  const [xAxis, setXAxis] = useState<string>('');
  const [yAxis, setYAxis] = useState<string>('');
  const [aggregation, setAggregation] = useState<'sum' | 'avg' | 'count' | 'max' | 'min'>('sum');
  const [groupBy, setGroupBy] = useState<string[]>([]);
  const [filters, setFilters] = useState<any[]>([]);

  const [previewData, setPreviewData] = useState<any[]>([]);
  const [columns, setColumns] = useState<string[]>([]);

  useEffect(() => {
    if (selectedDataset) {
      const dataset = datasets?.find(d => d.id === selectedDataset);
      if (dataset) {
        const data = dataset.uploadedData as any[];
        setColumns(Object.keys(data[0] || {}));
        processData(data);
      }
    }
  }, [selectedDataset, xAxis, yAxis, aggregation, groupBy, filters]);

  const processData = (rawData: any[]) => {
    if (!xAxis || !yAxis) {
      setPreviewData([]);
      return;
    }

    // Apply filters
    let filtered = rawData;
    filters.forEach(filter => {
      filtered = filtered.filter(row => {
        const value = row[filter.field];
        switch (filter.operator) {
          case 'eq': return value === filter.value;
          case 'gt': return value > filter.value;
          case 'lt': return value < filter.value;
          case 'contains': return String(value).includes(filter.value);
          default: return true;
        }
      });
    });

    // Group and aggregate
    if (groupBy.length > 0) {
      const grouped = new Map();

      filtered.forEach(row => {
        const key = groupBy.map(field => row[field]).join('::');
        if (!grouped.has(key)) {
          grouped.set(key, []);
        }
        grouped.get(key).push(row);
      });

      const aggregated = Array.from(grouped.entries()).map(([key, values]) => {
        const groupKeys = key.split('::');
        const result: any = {};

        groupBy.forEach((field, idx) => {
          result[field] = groupKeys[idx];
        });

        // Perform aggregation
        const nums = (values as any[]).map(v => Number(v[yAxis])).filter(n => !isNaN(n));
        switch (aggregation) {
          case 'sum':
            result[yAxis] = nums.reduce((a, b) => a + b, 0);
            break;
          case 'avg':
            result[yAxis] = nums.reduce((a, b) => a + b, 0) / nums.length;
            break;
          case 'count':
            result[yAxis] = values.length;
            break;
          case 'max':
            result[yAxis] = Math.max(...nums);
            break;
          case 'min':
            result[yAxis] = Math.min(...nums);
            break;
        }

        return result;
      });

      setPreviewData(aggregated);
    } else {
      setPreviewData(filtered.slice(0, 50)); // Limit preview to 50 rows
    }
  };

  const renderChart = () => {
    if (previewData.length === 0) return <div className="text-center text-muted-foreground p-8">Configure chart to see preview</div>;

    const chartProps = {
      data: previewData,
      margin: { top: 20, right: 30, left: 20, bottom: 20 }
    };

    switch (chartType) {
      case 'line':
        return (
          <ResponsiveContainer width="100%" height={400}>
            <LineChart {...chartProps}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey={xAxis} />
              <YAxis />
              <Tooltip />
              <Legend />
              <Line type="monotone" dataKey={yAxis} stroke="hsl(var(--primary))" />
            </LineChart>
          </ResponsiveContainer>
        );

      case 'bar':
        return (
          <ResponsiveContainer width="100%" height={400}>
            <BarChart {...chartProps}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey={xAxis} />
              <YAxis />
              <Tooltip />
              <Legend />
              <Bar dataKey={yAxis} fill="hsl(var(--primary))" />
            </BarChart>
          </ResponsiveContainer>
        );

      case 'area':
        return (
          <ResponsiveContainer width="100%" height={400}>
            <AreaChart {...chartProps}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey={xAxis} />
              <YAxis />
              <Tooltip />
              <Legend />
              <Area type="monotone" dataKey={yAxis} fill="hsl(var(--primary))" fillOpacity={0.6} stroke="hsl(var(--primary))" />
            </AreaChart>
          </ResponsiveContainer>
        );

      case 'pie':
        return (
          <ResponsiveContainer width="100%" height={400}>
            <PieChart>
              <Pie
                data={previewData}
                dataKey={yAxis}
                nameKey={xAxis}
                cx="50%"
                cy="50%"
                outerRadius={150}
                label
              >
                {previewData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={`hsl(${index * 45}, 70%, 50%)`} />
                ))}
              </Pie>
              <Tooltip />
              <Legend />
            </PieChart>
          </ResponsiveContainer>
        );
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
      {/* Configuration Panel */}
      <div className="lg:col-span-1 space-y-4">
        <Card>
          <CardHeader>
            <CardTitle>Chart Configuration</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div>
              <Label>Dataset</Label>
              <Select value={selectedDataset} onValueChange={setSelectedDataset}>
                <SelectTrigger>
                  <SelectValue placeholder="Select dataset" />
                </SelectTrigger>
                <SelectContent>
                  {datasets?.map(ds => (
                    <SelectItem key={ds.id} value={ds.id}>{ds.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>Chart Type</Label>
              <Select value={chartType} onValueChange={(v: any) => setChartType(v)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="line">Line Chart</SelectItem>
                  <SelectItem value="bar">Bar Chart</SelectItem>
                  <SelectItem value="pie">Pie Chart</SelectItem>
                  <SelectItem value="area">Area Chart</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>X-Axis (Dimension)</Label>
              <Select value={xAxis} onValueChange={setXAxis} disabled={!selectedDataset}>
                <SelectTrigger>
                  <SelectValue placeholder="Select field" />
                </SelectTrigger>
                <SelectContent>
                  {columns.map(col => (
                    <SelectItem key={col} value={col}>{col}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>Y-Axis (Metric)</Label>
              <Select value={yAxis} onValueChange={setYAxis} disabled={!selectedDataset}>
                <SelectTrigger>
                  <SelectValue placeholder="Select field" />
                </SelectTrigger>
                <SelectContent>
                  {columns.map(col => (
                    <SelectItem key={col} value={col}>{col}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>Aggregation</Label>
              <Select value={aggregation} onValueChange={(v: any) => setAggregation(v)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="sum">Sum</SelectItem>
                  <SelectItem value="avg">Average</SelectItem>
                  <SelectItem value="count">Count</SelectItem>
                  <SelectItem value="max">Maximum</SelectItem>
                  <SelectItem value="min">Minimum</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <Button 
              className="w-full" 
              onClick={() => onSave({
                datasetId: selectedDataset,
                type: chartType,
                xAxis,
                yAxis,
                aggregation,
                groupBy,
                filters
              })}
            >
              Save Chart
            </Button>
          </CardContent>
        </Card>
      </div>

      {/* Preview Panel */}
      <div className="lg:col-span-2">
        <Card>
          <CardHeader>
            <CardTitle>Chart Preview</CardTitle>
          </CardHeader>
          <CardContent>
            {renderChart()}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}
```

